import React, { useEffect, useState } from 'react';
import axios from 'axios';

const IssueReturn = () => {
  const [books, setBooks] = useState([]);
  const [members, setMembers] = useState([]);
  const [borrowForm, setBorrowForm] = useState({ bookId: '', dueDate: '' });
  const [returnId, setReturnId] = useState('');

  useEffect(() => {
    fetchBooks();
    fetchMembers();
  }, []);

  const fetchBooks = async () => {
    const res = await axios.get('http://localhost:5000/api/books');
    setBooks(res.data);
  };

  const fetchMembers = async () => {
    const token = localStorage.getItem('token');
    const res = await axios.get('http://localhost:5000/api/members', {
      headers: { Authorization: `Bearer ${token}` }
    });
    setMembers(res.data);
  };

  const handleIssue = async (e) => {
    e.preventDefault();
    const token = localStorage.getItem('token');
    await axios.post('http://localhost:5000/api/borrow/issue', borrowForm, {
      headers: { Authorization: `Bearer ${token}` }
    });
    alert('Book issued');
    fetchBooks();
  };

  const handleReturn = async (e) => {
    e.preventDefault();
    const token = localStorage.getItem('token');
    await axios.post(`http://localhost:5000/api/borrow/return/${returnId}`, {}, {
      headers: { Authorization: `Bearer ${token}` }
    });
    alert('Book returned');
    fetchBooks();
  };

  return (
    <div>
      <h1>Issue/Return Books</h1>
      <form onSubmit={handleIssue}>
        <select value={borrowForm.bookId} onChange={(e) => setBorrowForm({ ...borrowForm, bookId: e.target.value })} required>
          <option value="">Select Book</option>
          {books.map(book => (
            <option key={book._id} value={book._id}>{book.title}</option>
          ))}
        </select>
        <input type="date" value={borrowForm.dueDate} onChange={(e) => setBorrowForm({ ...borrowForm, dueDate: e.target.value })} required />
        <button type="submit">Issue Book</button>
      </form>
      <form onSubmit={handleReturn}>
        <input type="text" placeholder="Borrow Record ID" value={returnId} onChange={(e) => setReturnId(e.target.value)} required />
        <button type="submit">Return Book</button>
      </form>
    </div>
  );
};

export default IssueReturn;
